export interface Exoplanet {
    id: string;
    index: number;
    name: string;
    hostStar: string;
    letter: string;
    orbitalPeriodDays: number | null;
    semiMajorAxisAU: number | null;
    eccentricity: number | null;
    inclinationDeg: number | null;
    radiusEarth: number | null;
    radiusJupiter: number | null;
    massEarth: number | null;
    massJupiter: number | null;
    densityGCC: number | null;
    gravityMS2: number | null;
    equilibriumTempK: number | null;
    insolationFlux: number | null;
    planetType: PlanetType;
    discoveryMethod: DiscoveryMethod;
    discoveryYear: number | null;
    discoveryFacility: string | null;
    telescope: string | null;
    stellarTempK: number | null;
    stellarRadiusSun: number | null;
    stellarMassSun: number | null;
    stellarMetallicity: number | null;
    stellarAge: number | null;
    rightAscension: number | null;
    declination: number | null;
    distanceParsec: number | null;
    habitabilityScore: number;
    habitabilityClass: HabitabilityClass;
    referenceUrl: string | null;
    hasAtmosphereData: boolean;
    numberOfKnownPlanetsInSystem: number | null;
}
export type PlanetType = 'rocky-terrestrial' | 'super-earth' | 'mini-neptune' | 'neptunian' | 'jovian' | 'hot-jupiter' | 'cold-giant' | 'unknown';
export type DiscoveryMethod = 'Transit' | 'Radial Velocity' | 'Direct Imaging' | 'Microlensing' | 'Astrometry' | 'Transit Timing Variations' | 'Other';
export type HabitabilityClass = 'potentially-habitable' | 'marginal' | 'uninhabitable' | 'unknown';
